    keuzemomenten: "",
    samenhang_blokken: [{"naam": "Gebruikerservaring en toegankelijkheid", "omschrijving": "Confidence-indicatoren, disclaimers en mogelijkheden om naar een mens over te schakelen bepalen hoe de assistent ervaren wordt — kwaliteit is alleen merkbaar als de UI hem zichtbaar maakt."}, {"naam": "Technische Prestaties", "omschrijving": "Latency en kwaliteit zijn een trade-off. Meer evaluatie- en controlestappen kunnen het systeem trager en duurder maken; log per stap zowel kwaliteitswinst als extra latency en tokenverbruik."}, {"naam": "Functionaliteit", "omschrijving": "Agentische complexiteit (tools, memory) verandert de evaluatie-aanpak fundamenteel — niet meer alleen de eindoutput beoordelen maar ook tussenstappen, tool-calls en geheugenstate."}, {"naam": "Ethiek & Mensenrechten", "omschrijving": "Bias als kwaliteitsindicator, FRAIA-toetsing en non-discriminatie zijn ingebed in soft metrics. Test-sets met ethische cases overlappen met kwaliteits-test-sets."}, {"naam": "Governance", "omschrijving": "Eigenaarschap van de golden dataset, drempelwaarden en het auditproces worden hier bepaald. Zonder governance is een evaluatie-framework een geïsoleerd dashboard."}, {"naam": "Kennis en capaciteit", "omschrijving": "Domeinexperts zijn onmisbaar voor curatie en review van de golden dataset. Zonder hun tijd geen ground truth; zonder ground truth geen evaluatie."}, {"naam": "Infrastructuur & Data", "omschrijving": "Observability-tooling (MLflow, LangSmith, Langfuse), data-pipelines voor evaluatie en gestructureerde logging zijn de infrastructuur waarop kwaliteit gemeten wordt."}, {"naam": "Compliance", "omschrijving": "Aantoonbare kwaliteit is voorwaarde voor compliance met de AI-verordening en AVG. Een organisatie zonder evaluatie-bewijs kan haar AI niet auditeerbaar maken."}],
